var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아하핫, 신기하네. 이쪽 세계는 대전 액션이 아니라 라인 배틀로 싸우는 거야?","JPN":"アハハッ、面白いね。こっちの世界は対戦アクションじゃなくて、ラインバトルで戦うの？","ENG":"Ah hah hah, this is interesting. Are line battles more popular here than one-on-one fights?","TWN":"哈哈哈，真是奇妙，這個世界的打法竟然不是對打模式，而是無差別攻擊法？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"태그 매치도 없이 모두가 한꺼번에 전투를 벌이다니, 정신없는 환경이군.","JPN":"タッグマッチもなしで全員一斉に戦闘するなんて、なかなか慌ただしい環境だな。","ENG":"They come at once, instead of taking turns. This is a complete mess!","TWN":"而且也不是輪流上，一次全衝上來，有點應付不來呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그러게? 이렇게 뒤엉켜 싸우니까 내 화려한 기술이 네 엉덩이에 가려서 잘 안 보이잖아?","JPN":"そうね。こんなハチャメチャな環境じゃ、私の華麗なスキルがあんたのケツに邪魔されて見えないんじゃない！","ENG":"I couldn't agree more. We're entangled in such a fray that I can't see anything because of your butt. Move it, will you?","TWN":"就是說啊，這樣打成一團，我華麗的招式都被你的大屁股擋住看不到啦！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"스나이퍼 클래스면 걸리적거리지 말고 뒤로 빠져라, 원숭이.","JPN":"スナイパークラスなら邪魔しないで後ろに下がっていろ、サル。","ENG":"Stop getting in my way and stay behind, Sniper monkey.","TWN":"身為狙擊手少在那邊扯後腿，退到後面啦，臭猴子！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"헹, 너야말로 서포터가 왜 앞에서 알짱대는 건데?","JPN":"は？　あんたこそサポートのくせに前線でウロチョロするんじゃないよ。","ENG":"Hah! You're a Supporter. What are you doing in front of everyone?","TWN":"哼！你才是咧！身為輔助，在前面晃來晃去幹嘛？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"쯧.","JPN":"ちっ。","ENG":"Hmpf!","TWN":"嘖嘖！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우와앗! 침식체가 또 엄청나게 몰려오고 있어요!","JPN":"うわー！　ものすごい数の侵食体が再び押し寄せてきてます！","ENG":"Waaah! There's a whole bunch of them coming again!","TWN":"保安！侵蝕體可以這樣打完又來，打完又來的嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"함선이 곧 파괴될 것 같은데 지금이라도 도망칠까요?","JPN":"艦船が破壊されそうですけど、手遅れになる前に逃げますか？","ENG":"The ship is all but destroyed. Should we run now?","TWN":"艦船好像快毀掉咧？要棄船逃命嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"상관없어. 우린 아직 멀쩡하니까. 그깟 함선 하나쯤 없어져도 이길 수 있다고.","JPN":"いや。私たちはまだ全然平気だし、艦船一隻くらい消えても勝てるだろ？","ENG":"Doesn't matter. We're fine. We don't need the ship to beat them.","TWN":"不用！我們還能打！就算少一艘艦船，我們還是打得贏！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 그치만 함선이 파괴되면 저희도 자동으로 전멸인데요?","JPN":"え？　艦船が破壊されたら私たちも自動的に全滅になるんですよ？","ENG":"Huh? If the ship gets destroyed, we'll be wiped out automatically.","TWN":"不明白？艦船毀掉的話，等於我們自動全軍覆沒不是嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"뭐어? 말도 안 돼! 무슨 그런 순 억지 시스템이 다 있어?!","JPN":"はあ？　どういうことだ？　そんなめちゃくちゃなシステムが実在するの！？","ENG":"WHAT? That makes no sense! It's unfair!","TWN":"什麼？完全不合理！怎麼會有這麼蠢的系統？！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"확실히 말도 안 되긴 하네.","JPN":"確かにあり得ないことだ。","ENG":"It does make no sense.","TWN":"確實是很不合理。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"너 같이 다른 세계의 규칙도 숙지 못한 원숭이가 어떻게 우주 경찰이 된 거지?","JPN":"お前みたいな他の世界のルールも熟知できないサルがどうやって宇宙警察になれたんだ？","ENG":"Monkey, how did you become a space cop without learning the rules of different worlds?","TWN":"像你這種不熟悉其他世界規則的猴子，是怎麼當上宇宙警察的？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"멀쩡한 눈 가리고 면접 본 녀석한테 그런 소리 듣고 싶지 않거든?!","JPN":"健康極まりない目なのに眼帯して面接するやつにそんなこと言われてもね！","ENG":"You don't get to judge; you had your interview while covering a perfectly functioning eye!","TWN":"像你這種明明眼睛沒事，還硬要帶個眼罩面試的傢伙，應該沒資格說我吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저기. 지금 저희끼리 싸울 때가 아니지 않나요? 침식체가 뭘 쏘려는 것 같은데요!","JPN":"あのー、今言い争いしている場合じゃないと思いますよ？　侵食体が何か撃ってきそうです！","ENG":"Hey, I don't think this is a good time for us to fight. That C.O. is about to fire something at us!","TWN":"我說，現在不是搞內鬨的時候吧！侵蝕體好像要發射什麼的樣子欸！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};